window.addEventListener("DOMContentLoaded",()=>{const nav=document.body.querySelector("#mainNav");const toggler=document.body.querySelector(".navbar-toggler");if(!nav){return}const isStaticNav=nav.dataset.staticNav==="true";const updateNav=()=>{if(isStaticNav||window.scrollY!==0){nav.classList.add("navbar-shrink")}else{nav.classList.remove("navbar-shrink")}};updateNav();if(!isStaticNav){document.addEventListener("scroll",updateNav);new bootstrap.ScrollSpy(document.body,{target:"#mainNav",rootMargin:"0px 0px -40%"})}[].slice.call(document.querySelectorAll("#navbarResponsive .nav-link")).forEach(link=>{link.addEventListener("click",()=>{if(toggler&&window.getComputedStyle(toggler).display!=="none"){toggler.click()}})})});